// Controller

using System.Linq;
using System.Web.Mvc;
using YourNamespace.Models;
using YourNamespace.Data;

namespace YourNamespace.Controllers
{
    public class ProductController : Controller
    {
        private ApplicationDbContext _context;

        public ProductController()
        {
            _context = new ApplicationDbContext();
        }

        public ActionResult Reviews(int id)
        {
            var reviews = _context.Reviews.Where(r => r.ProductId == id).ToList();
            return View(reviews);
        }
    }
}

// Model

namespace YourNamespace.Models
{
    public class Review
    {
        public int Id { get; set; }
        public int ProductId { get; set; }
        public string UserName { get; set; }
        public string Content { get; set; }
    }
}

// View (Reviews.cshtml)

@model List<YourNamespace.Models.Review>

@foreach (var review in Model)
{
    <div>
        <h3>@review.UserName</h3>
        <p>@Html.Raw(HttpUtility.HtmlEncode(review.Content))</p>
    </div>
}

// Note: The above code assumes that you have a database context (ApplicationDbContext) set up with a Reviews DbSet. Make sure to replace "YourNamespace" with the actual namespace you're using in your project.